{
global:
    extern "C++" {
        # Match Create by name (glob), not a quoted exact signature: a quoted
        # signature like "mylib::Create()" warns on MSVC, where name-only
        # demangling has no signature to match. The glob's `*` covers the `()`
        # in the GNU-ld demangled name and the empty suffix in the MSVC
        # name-only form, so it selects the symbol on every platform.
        mylib::Create*;
        # Export every member of mylib::Api (Greet, the implicit ctor, ...).
        # (Api has no virtual functions here, so there is no vtable/typeinfo to
        # export; a polymorphic class would also need `vtable?for?mylib::Api`
        # and `typeinfo?for?mylib::Api` -- see the docs.)
        mylib::Api::*;
    };
local:
    # Everything else stays hidden -- notably the external-linkage helper
    # mylib::Decorate in api.cc.
    *;
};
